// === src/pages/Shop.js ===
import React, { useEffect, useState } from 'react';
import './Shop.css';

// 💡 Only allow edit/delete for admin-added products (based on presence of `description`)
const handleDelete = (productToDelete) => {
  const all = JSON.parse(localStorage.getItem('products')) || [];
  const updated = all.filter(p => p.name !== productToDelete.name);
  localStorage.setItem('products', JSON.stringify(updated));
  window.location.reload();
};

const handleEdit = (productToEdit) => {
  alert("This would open a modal or edit form for product: " + productToEdit.name);
  // You can pass the item to localStorage or context and open an editable form
};

const defaultSections = {
  Plants: [
  ],
  Flowers: [
  ],
  Seeds: [
  ],
  Pots: [
  ],
  Decor: [
    {
      name: 'Miniature Fencing',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/fence_decor.jpg',
      price: 79,
    },
    {
      name: 'Wooden Tray',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/wood_tray.jpg',
      price: 129,
    },
  ],
};

const Shop = () => {
  const [shopData, setShopData] = useState(defaultSections);

  useEffect(() => {
    const added = JSON.parse(localStorage.getItem('products')) || [];

    const updatedSections = { ...defaultSections };

    added.forEach((item) => {
      const cat = item.category || 'Plants';
      if (!updatedSections[cat]) updatedSections[cat] = [];
      updatedSections[cat].push(item);
    });

    setShopData(updatedSections);
  }, []);

  return (
    <div className="shop-container">
      <h2 className="shop-title">Shop All Categories</h2>

      {Object.entries(shopData).map(([category, items], idx) => (
        <div key={idx} className="shop-section">
          <h3>{category}</h3>
          <div className="shop-grid">
            {items.map((item, i) => (
              <div className="product-card" key={i}>
                <img src={item.image} alt={item.name} />
                <h4>{item.name}</h4>
                <p>₹{item.price}</p>

                {/* 🛠️ Show edit/delete only for admin-added products */}
                {item.description && (
                  <div className="admin-actions">
                    <button onClick={() => handleEdit(item)}>Edit</button>
                    <button onClick={() => handleDelete(item)}>Delete</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default Shop;
